+            let name = path.file_name().and_then(|s| s.to_str()).unwrap_or("");
+            if name.starts_with("session-") && name.ends_with(".json") {
+                // Verify it's in a chats/ directory
+                if path
+                    .parent()
+                    .and_then(|p| p.file_name())
+                    .and_then(|n| n.to_str())
+                    == Some("chats")
+                {
+                    files.push(path.to_path_buf());
+                }
+            }
+        }
+        files
+    }
